          </text>
        </g>
        
        <!-- Q1 -->
        <g transform="translate(-80, 0)">
          <line x1="0" y1="0" x2="20" y2="0" stroke="#a855f7" stroke-width="2.5" stroke-dasharray="6,4" />
          <text x="24" y="4" :fill="svgColors.legendText" font-size="11" font-family="'DM Sans', sans-serif" font-weight="500">
            Q1
          </text>
        </g>
        
        <!-- Median -->
        <g transform="translate(-20, 0)">
          <line x1="0" y1="0" x2="20" y2="0" stroke="#8b5cf6" stroke-width="3" stroke-dasharray="6,4" />
          <text x="24" y="4" :fill="svgColors.legendText" font-size="11" font-family="'DM Sans', sans-serif" font-weight="500">
            Median
          </text>
        </g>
        
        <!-- Average -->
        <g transform="translate(60, 0)">
          <line x1="0" y1="0" x2="20" y2="0" stroke="#f97316" stroke-width="3" stroke-dasharray="6,4" />
          <text x="24" y="4" :fill="svgColors.legendText" font-size="11" font-family="'DM Sans', sans-serif" font-weight="500">
            Avg
          </text>
        </g>
        
        <!-- Q3 -->
        <g transform="translate(130, 0)">
          <line x1="0" y1="0" x2="20" y2="0" stroke="#7c3aed" stroke-width="2.5" stroke-dasharray="6,4" />
          <text x="24" y="4" :fill="svgColors.legendText" font-size="11" font-family="'DM Sans', sans-serif" font-weight="500">
            Q3
          </text>
        </g>
        
        <!-- Max -->
        <g transform="translate(180, 0)">
          <line x1="0" y1="0" x2="20" y2="0" stroke="#C67DFF" stroke-width="2.5" stroke-dasharray="6,4" />
          <text x="24" y="4" :fill="svgColors.legendText" font-size="11" font-family="'DM Sans', sans-serif" font-weight="500">
            Max
          </text>
        </g>
      </g>

      <!-- Tooltip último en el SVG para que pinte por encima de barras / curva / líneas -->
      <g
        v-if="interactive && tooltip.visible"
        pointer-events="none"
        :transform="`translate(${tooltip.x}, ${tooltip.y})`"
      >
        <rect
          filter="url(#histogram-tooltip-shadow)"
          :x="-tooltip.width / 2"
          :y="-tooltip.height - 10"
          :width="tooltip.width"
          :height="tooltip.height"
          :fill="tooltipPalette.bg"
          rx="8"
          :stroke="tooltipPalette.border"
          stroke-width="1"
        />
        <text
          x="0"
          :y="-tooltip.height - 10 + tooltipPadV"
          text-anchor="middle"
          :fill="tooltipPalette.text"
          font-size="13"
          font-weight="600"
          font-family="'DM Sans', sans-serif"
          dominant-baseline="hanging"
        >
          {{ tooltip.title }}
        </text>
        <text
          x="0"
          :y="-tooltip.height - 10 + tooltipPadV + tooltipTitleLine + tooltipLineGap"
          text-anchor="middle"
          :fill="tooltipPalette.secondary"
          font-size="12"
          font-weight="500"
          font-family="'DM Sans', sans-serif"
          dominant-baseline="hanging"
        >
          {{ tooltip.text }}
        </text>
      </g>
    </svg>
  </div>
</template>

<script setup lang="ts">
import { computed, ref, toRef } from 'vue';
import { useThemeDetection, type Theme } from '../../../composables/useThemeDetection';

interface HistogramItem {
  score: number;
  count: number;
}

const props = withDefaults(defineProps<{
  histogram: HistogramItem[];
  minScore?: number;
  maxScore?: number;
  q1Score?: number;
  medianScore?: number;
  q3Score?: number;
  averageScore?: number;
  chartWidth?: number;
  chartHeight?: number;
  chartMargin?: number;
  chartMarginRight?: number;
  chartBottomMargin?: number;
  plotInset?: number;
  showLegend?: boolean;
  showStatLabels?: boolean;
  /** When false, disables tooltip, cursor change, and hover styling on bars/container/curve */
  interactive?: boolean;
  theme?: Theme;
}>(), {
  histogram: () => [],
  minScore: 0,
  maxScore: 0,
  q1Score: 0,
  medianScore: 0,
  q3Score: 0,
  averageScore: 0,
  chartWidth: 800,
  chartHeight: 450,
  chartMargin: 60,
  chartMarginRight: undefined,
  chartBottomMargin: 80,
  plotInset: 6,
  showLegend: true,
  showStatLabels: true,
  interactive: true,
  theme: undefined
});

// Theme detection with prop fallback
const { isDark, colors } = useThemeDetection(toRef(props, 'theme'));

/** Padding tooltip como ECharts Sankey `[10, 14]` */
const tooltipPadV = 10;
const tooltipPadH = 14;
const tooltipTitleLine = 13;
const tooltipBodyLine = 12;
const tooltipLineGap = 4;
const tooltipHeightFixed =
  tooltipPadV + tooltipTitleLine + tooltipLineGap + tooltipBodyLine + tooltipPadV;

const tooltipPalette = computed(() => ({
  bg: colors.value.tooltipBg,
  border: colors.value.tooltipBorder,
  text: colors.value.tooltipText,
  secondary: isDark.value ? '#d1d5db' : '#e2e8f0',
}));

/**
 * Ancho horizontal aproximado por línea (DM Sans latino; título suele llevar más peso).
 * Así la caja = padH*2 + max(líneas) deja espacio izquierdo y derecho igual respecto al bloque de texto.
 */
function approximateSvgLineWidth(charCount: number, fontSizePx: number, semiBold: boolean): number {
  const em = semiBold ? 0.6 : 0.535;
  return Math.ceil(Math.max(charCount, 1) * fontSizePx * em);
}

function estimateTooltipWidth(title: string, text: string): number {
  const inner = Math.max(
    approximateSvgLineWidth(title.length, tooltipTitleLine, true),
    approximateSvgLineWidth(text.length, tooltipBodyLine, false),
    52,
  );
  return inner + tooltipPadH * 2;
}

function clampTooltipPosition(
  x: number,
  y: number,
  width: number,
  height: number,
): { x: number; y: number } {
  const half = width / 2;
  const viewportPad = 6;
  const cx = Math.min(
    Math.max(x, half + viewportPad),
    props.chartWidth - half - viewportPad,
  );
  /** Rect: top = y - height - 10, bottom = y - 10 (coords SVG) */
  const minY = viewportPad + height + 10;
  const maxY = props.chartHeight - viewportPad + 10;
  const cy = Math.min(Math.max(y, minY), maxY);
  return { x: cx, y: cy };
}

// SVG colors based on theme
const svgColors = computed(() => ({
  // Axis
  axis: isDark.value ? '#9ca3af' : '#475569',
  // Grid
  gridLine: isDark.value ? '#374151' : '#e5e7eb',
  // Ticks
  tickLine: isDark.value ? '#4b5563' : '#cbd5e1',
  tickText: isDark.value ? '#9ca3af' : '#64748b',
  // Labels
  labelText: isDark.value ? '#d1d5db' : '#475569',
  legendText: isDark.value ? '#d1d5db' : '#475569',
}));

const tooltip = ref({
  visible: false,
  x: 0,
  y: 0,
  title: '',
  text: '',
  width: 0,
  height: 0,
  /** Centro SVG X de la barra activa; fija tooltip horizontal sobre la columna correcta cuando el SVG escala por CSS */
  anchorX: null as number | null,
});

const chartMarginRightResolved = computed(
  () => props.chartMarginRight ?? props.chartMargin,
);

const plotLeft = computed(() => props.chartMargin + props.plotInset);
const plotRight = computed(
  () => props.chartWidth - chartMarginRightResolved.value - props.plotInset,
);
const plotWidth = computed(() => Math.max(plotRight.value - plotLeft.value, 1));
const plotHeight = computed(() => props.chartHeight - props.chartMargin - props.chartBottomMargin);
const barWidth = computed(() => (plotWidth.value / 10) * 0.52);

function valueToX(value: number): number | null {
  if (value < 1 || value > 10) return null;
  const barSpacing = plotWidth.value / 10;
  return plotLeft.value + (value - 0.5) * barSpacing;
}

const xAxisTicks = computed(() =>
  Array.from({ length: 10 }, (_, index) => {
    const score = index + 1;
    const x = valueToX(score);
    return x === null ? null : { score, x };
  }).filter((tick): tick is { score: number; x: number } => tick !== null),
);

const maxCount = computed(() => {
  if (!props.histogram || props.histogram.length === 0) return 1;
  const actualMax = Math.max(...props.histogram.map(item => item.count || 0), 1);
  const padding = Math.max(1, Math.ceil(actualMax * 0.2));
  return actualMax + padding;
});

// Calculate standard deviation from histogram data
const standardDeviation = computed(() => {
  if (!props.histogram || props.histogram.length === 0) return 1;
  
  const mean = props.averageScore || 0;
  let totalCount = 0;
  let sumSquaredDiff = 0;
  
  props.histogram.forEach(item => {
    const count = item.count || 0;
    totalCount += count;
    const diff = item.score - mean;
    sumSquaredDiff += count * (diff * diff);
  });
  
  if (totalCount === 0) return 1;
  
  const variance = sumSquaredDiff / totalCount;
  return Math.sqrt(variance) || 1;
});

// Gaussian probability density function
const gaussianFunction = (x: number, mean: number, stdDev: number) => {
  if (stdDev === 0) return 0;
  const coefficient = 1 / (stdDev * Math.sqrt(2 * Math.PI));
  const exponent = -0.5 * Math.pow((x - mean) / stdDev, 2);
  return coefficient * Math.exp(exponent);
};

// Generate Gaussian bell curve path scaled to match tallest bar
const gaussianPath = computed(() => {
  if (!props.histogram || props.histogram.length === 0) return null;
  if (props.averageScore === 0 && standardDeviation.value === 0) return null;

  const mean = props.averageScore;
  const stdDev = standardDeviation.value;
  const numPoints = 100;

  const actualMax = Math.max(...props.histogram.map(item => item.count || 0), 1);
  const tallestBarHeight = (actualMax / maxCount.value) * plotHeight.value;
  if (tallestBarHeight <= 0) return null;

  let maxGaussianValue = 0;
  for (let i = 0; i <= numPoints; i++) {
    const x = 1 + 9 * (i / numPoints);
    const g = gaussianFunction(x, mean, stdDev);
    if (g > maxGaussianValue) maxGaussianValue = g;
  }
  if (maxGaussianValue <= 0) return null;

  const scaleFactor = tallestBarHeight / maxGaussianValue;

  const points: string[] = [];
  for (let i = 0; i <= numPoints; i++) {
    const x = 1 + 9 * (i / numPoints);
    const scaledValue = gaussianFunction(x, mean, stdDev) * scaleFactor;
    const xCoord = valueToX(x);
    if (xCoord !== null) {
      const yCoord = props.chartHeight - props.chartBottomMargin - scaledValue;
      points.push(`${i === 0 ? 'M' : 'L'} ${xCoord} ${yCoord}`);
    }
  }

  return points.join(' ');
});

const histogramData = computed(() => {
  if (!props.histogram || props.histogram.length === 0) return [];
  
  const barSpacing = plotWidth.value / 10;
  return props.histogram.map((item) => {
    const score = Number(item.score);
    if (!Number.isFinite(score) || score < 1 || score > 10) {
      return null;
    }
    const x = plotLeft.value + (score - 0.5) * barSpacing;
    const height = item.count > 0 ? (item.count / maxCount.value) * plotHeight.value : 0;
    const y = props.chartHeight - props.chartBottomMargin - height;
    
    return {
      score,
      count: item.count,
      x,
      y,
      height,
    };
  }).filter((bar): bar is NonNullable<typeof bar> => bar !== null);
});

const minX = computed(() => valueToX(props.minScore));
const maxX = computed(() => valueToX(props.maxScore));
const q1X = computed(() => valueToX(props.q1Score));
const medianX = computed(() => valueToX(props.medianScore));
const q3X = computed(() => valueToX(props.q3Score));
const averageX = computed(() => valueToX(props.averageScore));

const minValue = computed(() => props.minScore);
const maxValue = computed(() => props.maxScore);
const q1Value = computed(() => props.q1Score);
const medianValue = computed(() => props.medianScore);
const q3Value = computed(() => props.q3Score);
const averageValue = computed(() => props.averageScore);

// Sistema de posicionamiento de etiquetas con detección de colisiones
interface LabelPosition {
  x: number | null;
  y: number;
  value: number;
  label: string;
  color: string;
  id: string;
  width: number;
}

// Calcular posiciones de etiquetas superiores (Q1, Median, Avg, Q3) con detección de colisiones
const topLabelPositions = computed(() => {
  const labels: LabelPosition[] = [];
  const baseY = props.chartMargin - 8;
  const levelHeight = 18; // Espacio vertical entre niveles
  
  // Recopilar todas las etiquetas que van arriba, con sus anchos aproximados
  if (q1X.value !== null) {
    labels.push({ 
      x: q1X.value, 
      y: baseY, 
      value: props.q1Score, 
      label: `Q1: ${q1Value.value.toFixed(1)}`,
      color: '#a855f7',
      id: 'q1',
      width: 55
    });
  }
  if (medianX.value !== null) {
    labels.push({ 
      x: medianX.value, 
      y: baseY - levelHeight, 
      value: props.medianScore, 
      label: `Median: ${medianValue.value.toFixed(1)}`,
      color: '#8b5cf6',
      id: 'median',
      width: 90
    });
  }
  if (averageX.value !== null) {
    labels.push({ 
      x: averageX.value, 
      y: baseY - levelHeight, 
      value: props.averageScore, 
      label: `Avg: ${averageValue.value.toFixed(1)}`,
      color: '#f97316',
      id: 'avg',
      width: 65
    });
  }
  if (q3X.value !== null) {
    labels.push({ 
      x: q3X.value, 
      y: baseY, 
      value: props.q3Score, 
      label: `Q3: ${q3Value.value.toFixed(1)}`,
      color: '#7c3aed',
      id: 'q3',
      width: 55
    });
  }
  
  // Ordenar por posición X
  labels.sort((a, b) => (a.x || 0) - (b.x || 0));
  
  // Agrupar etiquetas por niveles y detectar colisiones
  // Crear niveles de posición vertical
  const levels: LabelPosition[][] = [[], [], []]; // 3 niveles posibles
  
  labels.forEach(label => {
    if (label.x === null) return;
    
    // Encontrar el nivel apropiado sin colisiones
    let assignedLevel = -1;
    
    for (let levelIdx = 0; levelIdx < levels.length; levelIdx++) {
      let hasCollision = false;
      
      for (const existingLabel of levels[levelIdx]) {
        if (existingLabel.x === null) continue;
        
        // Verificar si hay superposición horizontal
        const distance = Math.abs(label.x - existingLabel.x);
        const minDistance = (label.width + existingLabel.width) / 2 + 10;
        
        if (distance < minDistance) {
          hasCollision = true;
          break;
        }
      }
      
      if (!hasCollision) {
        assignedLevel = levelIdx;
        break;
      }
    }
    
    // Si no encontró nivel sin colisión, usar el último
    if (assignedLevel === -1) {
      assignedLevel = levels.length - 1;
    }
    
    // Asignar posición Y basada en el nivel
    label.y = baseY - (assignedLevel * levelHeight);
    levels[assignedLevel].push(label);
  });
  
  // Asegurar que las etiquetas no salgan del viewBox (límite superior)
  const minY = 15;
  labels.forEach(label => {
    if (label.y < minY) {
      label.y = minY;
    }
  });
  
  return labels;
});

// Función helper para obtener la posición Y de una etiqueta específica
const getLabelY = (id: string): number => {
  const label = topLabelPositions.value.find(l => l.id === id);
  return label?.y || props.chartMargin - 10;
};

const yAxisTicks = computed(() => {
  const ticks = [];
  const numTicks = 5;
  for (let i = 0; i <= numTicks; i++) {
    const value = Math.round((maxCount.value / numTicks) * i);
    const y = props.chartHeight - props.chartBottomMargin - (i / numTicks) * plotHeight.value;
    ticks.push({ value, y });
  }
  return ticks;
});

/**
 * Coordenadas del puntero en espacio de usuario SVG (coinciden con viewBox),
 * imprescindible cuando el SVG escala por `w-full`/responsive (ratio ≠ 1 vs rect local).
 */
function clientXYToSvgUserSpace(svg: SVGSVGElement, clientX: number, clientY: number) {
  const p = svg.createSVGPoint();
  p.x = clientX;
  p.y = clientY;
  const ctm = svg.getScreenCTM();
  if (!ctm) {
    const r = svg.getBoundingClientRect();
    return { x: clientX - r.left, y: clientY - r.top };
  }
  const loc = p.matrixTransform(ctm.inverse());
  return { x: loc.x, y: loc.y };
}

const onBarMouseEnter = (event: MouseEvent, bar: any) => {
  if (!props.interactive) return;
  showTooltip(event, bar);
};

const onBarMouseLeave = () => {
  if (!props.interactive) return;
  hideTooltip();
};

const showTooltip = (event: MouseEvent, bar: any) => {
  const svg = (event.currentTarget as SVGElement).closest('svg') as SVGSVGElement | null;
  if (!svg) return;

  const { x: px, y: py } = clientXYToSvgUserSpace(svg, event.clientX, event.clientY);

  const title = `Score: ${bar.score}`;
  const text = `Count: ${Number(bar.count ?? 0).toLocaleString()}`;
  const tooltipWidth = estimateTooltipWidth(title, text);
  const tooltipHeight = tooltipHeightFixed;

  /** Eje horizontal: centro de barra para alinear tooltip con la columna salvo efectos de escalado viewport */
  const x = typeof bar?.x === 'number' ? bar.x : px;
  let y = py - 20;
  const clamped = clampTooltipPosition(x, y, tooltipWidth, tooltipHeight);

  tooltip.value = {
    visible: true,
    x: clamped.x,
    y: clamped.y,
    title,
    text,
    width: tooltipWidth,
    height: tooltipHeight,
    anchorX: typeof bar?.x === 'number' ? bar.x : null,
  };
};

const handleMouseMove = (event: MouseEvent) => {
  if (!props.interactive) return;
  if (tooltip.value.visible) {
    const svg = event.currentTarget as SVGSVGElement;
    const { x: px, y: py } = clientXYToSvgUserSpace(svg, event.clientX, event.clientY);

    const anchor = tooltip.value.anchorX;
    const x = anchor != null && Number.isFinite(anchor) ? anchor : px;
    let y = py - 20;
    const clamped = clampTooltipPosition(x, y, tooltip.value.width, tooltip.value.height);
    tooltip.value.x = clamped.x;
    tooltip.value.y = clamped.y;
  }
};

const handleMouseLeave = () => {
  hideTooltip();
};

const hideTooltip = () => {
  tooltip.value.visible = false;
  tooltip.value.anchorX = null;
};

// Expose isDark for potential use
defineExpose({ isDark });
</script>

