<template>
  <ChartMetricContainer
    class="select-language-root h-full min-h-0"
    title="Language Selection"
    subtitle="Language distribution across conversations"
    :collapsible="false"
    :loading="props.loading"
  >
    <Transition name="bm-fade" mode="out-in">
      <div
        v-if="props.loading"
        key="loading"
        class="bm-status shrink-0"
        aria-busy="true"
        aria-label="Loading chart"
      >
        <div class="flex-1 bm-skeleton-blink" aria-hidden="true"></div>
      </div>

      <div v-else key="content" class="card-body">
      <template v-if="hasData">
        <div
          class="distribution-with-total flex w-full min-w-0 flex-1 flex-col gap-3 min-h-0"
        >
          <section class="pie-section">
            <PieChart :data="pieData" :options="pieOptions" />
          </section>
          <CardInfo
            class="shrink-0"
            title="Total"
            :value="useNumberFormat(totalCount)"
            color="#8b5cf6"
          />
        </div>
      </template>

      <!-- Empty State -->
      <section v-else class="empty-state">
        <div class="empty-state-content">
          <div class="empty-icon-wrapper">
            <svg
              class="empty-icon"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                stroke-linecap="round"
                stroke-linejoin="round"
                stroke-width="2"
                d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129"
              />
            </svg>
          </div>
          <p class="empty-title">No language data available</p>
          <p class="empty-description">
            No language selection data found for the selected period. Try
            adjusting the date range.
          </p>
        </div>
      </section>
    </div>
    </Transition>
  </ChartMetricContainer>
</template>

<script setup lang="ts">
import { computed, toRef } from "vue";
import PieChart from "../../Pie/PieChart.vue";
import CardInfo from "../../Utils/CardInfo/CardInfo.vue";
import ChartMetricContainer from "../../Utils/ChartMetricContainer/ChartMetricContainer.vue";
import { useNumberFormat } from "../../../../plugins/numberFormat";
import {
  useThemeDetection,
  type Theme,
} from "../../../../composables/useThemeDetection";

interface LanguageDayItem {
  date: string;
  language: string;
  count: number;
}

interface SelectLanguageData {
  items: LanguageDayItem[];
}

const props = withDefaults(
  defineProps<{
    data?: SelectLanguageData;
    loading?: boolean;
    theme?: Theme;
    enableExport?: boolean;
    exportLoading?: boolean;
  }>(),
  {
    data: () => ({ items: [] }),
    loading: false,
    theme: undefined,
    enableExport: false,
    exportLoading: false,
  },
);

const { isDark, colors } = useThemeDetection(toRef(props, "theme"));

const languageColors = [
  "#8b5cf6",
  "#06b6d4",
  "#f59e0b",
  "#10b981",
  "#ef4444",
  "#ec4899",
  "#6366f1",
  "#14b8a6",
  "#f97316",
  "#84cc16",
];

const LANGUAGE_MAP: Record<string, { label: string }> = {
  es: { label: "Spanish" },
  en: { label: "English" },
  pt: { label: "Portuguese" },
  fr: { label: "French" },
  de: { label: "German" },
  it: { label: "Italian" },
  ja: { label: "Japanese" },
  zh: { label: "Chinese" },
  ko: { label: "Korean" },
  ru: { label: "Russian" },
};

const getLanguageLabel = (code: string): string =>
  LANGUAGE_MAP[code]?.label || code.toUpperCase();

const hasData = computed(
  () => props.data?.items && props.data.items.length > 0,
);

const totalCount = computed(() =>
  (props.data?.items || []).reduce((sum, item) => sum + item.count, 0),
);

const languageSummary = computed(() => {
  const map: Record<string, number> = {};
  for (const item of props.data?.items || []) {
    map[item.language] = (map[item.language] || 0) + item.count;
  }
  return Object.entries(map)
    .map(([language, count]) => ({ language, count }))
    .sort((a, b) => b.count - a.count);
});

const pieData = computed(() => ({
  labels: languageSummary.value.map((lang) => getLanguageLabel(lang.language)),
  datasets: [
    {
      data: languageSummary.value.map((lang) => lang.count),
      backgroundColor: languageSummary.value.map(
        (_, idx) => languageColors[idx % languageColors.length] + "80",
      ),
      borderColor: languageSummary.value.map(
        (_, idx) => languageColors[idx % languageColors.length],
      ),
      borderWidth: 2,
      hoverOffset: 6,
    },
  ],
}));

const pieOptions = computed(() => ({
  responsive: true,
  maintainAspectRatio: false,
  cutout: "55%",
  plugins: {
    legend: {
      display: true,
      position: "bottom" as const,
      labels: {
        usePointStyle: true,
        pointStyle: "circle",
        padding: 16,
        font: { family: "'DM Sans', sans-serif", size: 12 },
        color: colors.value.textSecondary,
      },
    },
    tooltip: {
      backgroundColor: colors.value.tooltipBg,
      titleColor: colors.value.tooltipText,
      bodyColor: colors.value.tooltipText,
      borderColor: isDark.value
        ? "rgba(198, 125, 255, 0.2)"
        : "rgba(0, 0, 0, 0.1)",
      borderWidth: 1,
      padding: 12,
      cornerRadius: 8,
      titleFont: {
        family: "'Space Grotesk', sans-serif",
        size: 13,
        weight: 600 as any,
      },
      bodyFont: { family: "'DM Sans', sans-serif", size: 12 },
      callbacks: {
        label: (ctx: any) => {
          const value = ctx.raw || 0;
          const pct =
            totalCount.value > 0
              ? ((value / totalCount.value) * 100).toFixed(1)
              : "0";
          return ` ${ctx.label}: ${value} (${pct}%)`;
        },
      },
    },
  },
}));

defineExpose({ isDark });
</script>

